      case e: Exception => Failure(new SecurityException(s"Failed to parse XML configuration securely: ${e.getMessage}", e))
    }
  }
  
  private def extractSettings(xml: Node): ConfigurationSettings = {
    val settings = (xml \ "settings" \ "setting").map { setting =>
      val key = (setting \ "@key").text
      val value = (setting \ "@value").text.trim
      key -> value
    }.toMap
    
    val metadata = (xml \ "metadata" \ "meta").map { meta =>
      val key = (meta \ "@name").text
      val value = (meta \ "@content").text.trim
      key -> value
    }.toMap
    
    ConfigurationSettings(settings, metadata)
  }
  
  def parseConfigurationWithValidation(xmlString: String, allowedKeys: Set[String]): Try[ConfigurationSettings] = {
    parseConfiguration(xmlString).flatMap { config =>
      val invalidKeys = config.settings.keySet.diff(allowedKeys)
      if (invalidKeys.nonEmpty) {
        Failure(new IllegalArgumentException(s"Invalid configuration keys found: ${invalidKeys.mkString(", ")}"))
      } else {
        Success(config)
      }
    }
  }
  
  def getSetting(xmlString: String, key: String): Try[Option[String]] = {
    parseConfiguration(xmlString).map(_.settings.get(key))
  }
  
  def getAllSettings(xmlString: String): Try[Map[String, String]] = {
